var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 전 소대, 배치 완료.","JPN":" 全小隊、配置完了。","ENG":"All units, in formation.","TWN":"所有小隊佈署完畢。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 카운터들도 지정된 위치에서 대기 중입니다.","JPN":" カウンターたちも指定の場所で待機しています。","ENG":"The Counters are standing by in their designated positions.","TWN":"制裁者也都就指定位置待命。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 좋아. 곧 요인이 승강기를 타고 내려올 거다. ","JPN":" よし、もうすぐ要人がエレベーターで降りてくる。 ","ENG":"Good. The VIP will soon come down via the elevator.","TWN":"很好，VIP馬上就會搭電梯下來。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 전원 임무 중 긴장을 놓지 마라. 도시 한복판이라고 방심하지 말고.","JPN":" 全員任務中は気を抜くな。街のど真ん中とはいえ油断は禁物だ。","ENG":"All units are to stay vigilant during the mission. And do not let your guard down just because it is an urban area.","TWN":"大家值勤中保持戒備，這裡可是市中心，不能大意。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 그나저나 안타깝네요. 슈나이더 부인 말이에요.","JPN":" それにしても気の毒でしたね。シュナイダー夫人。","ENG":"I mean, it's a shame, with Mrs. Schneider.","TWN":"不過修奈德夫人還真可憐。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 그림자들이 노리다니……. 저 같으면 하루하루가 악몽 같겠어요.","JPN":" シャドウに狙われるなんて……私なら毎日が地獄だったでしょう。","ENG":"To be hunted down by Shadows... Every day would feel like a nightmare if it were me.","TWN":"暗影竟然想對她下手……要是我應該每天都像活在惡夢裡吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" ……어, 음? 방금 누가 지나가지 않았어?","JPN":" ……え、うむ？　今誰か通らなかったか？","ENG":"...Hmm? Did someone just pass by?","TWN":"……嗯？剛剛是不是有人經過？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 네? 지나가다니요?","JPN":" はい？　通るって、何がですか？","ENG":"Huh? Who passed by?","TWN":"有嗎？誰經過？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 아니야. 내가 뭔가 착각했나 봐.","JPN":" いや、なんでもない。気のせいだったようだ。","ENG":"Never mind. I guess I'm seeing things.","TWN":"沒有啦，應該是我眼花。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 그보다 잠깐 기다려.","JPN":" それより少し待て。","ENG":"But wait a second.","TWN":"你先等我一下。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 네? 왜 그러세요?","JPN":" はい？　どうされました？","ENG":"Yes? What's the matter?","TWN":"怎麼了嗎？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 기껏 한다는 게 늙은이 뒷바라지라니까 갑자기 살기가 싫어져서.","JPN":" ご老人の後始末なんかやらされる人生だと思ったら死にたくなった。","ENG":"I don't want to live anymore taking care of some old hag.","TWN":"一直在做些看護的事，突然覺得不想活了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"SOLDIER_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" ……아. 그렇네요.","JPN":" ……確かに、そうですね。","ENG":"...Ah. I agree.","TWN":"……也是。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 열심히 일해 봤자 침식체는 계속 나타나고 월급을 모아도 길어야 백 년 살고 죽을 텐데.","JPN":" いくら頑張って働いたって侵食体はいなくなりませんし、いくら給料があっても100年ぐらいでどうせ死にますし。","ENG":"Hard work won't stop the C.O.s from coming, and I'm not going to live past 100 with this salary.","TWN":"努力工作侵蝕體還是一直出現，就算把薪水都存起來，長壽一點的話還要活到一百歲。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":" 잠깐 위에 갔다 올게요. 머리부터 먼저 떨어지면 3층에서 추락해도 충분하겠죠.","JPN":" ちょっと上に行ってきます。頭から落ちれば3階でも十分死ねますよね。","ENG":"I'm going to go upstairs. The third floor should be enough if I fall head first.","TWN":"我上去一下，頭先著地的話，從三樓跳下來應該也必死無疑吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":" 누구세요……?","JPN":" どちら様でしょうか……？","ENG":"Who are you...?","TWN":"是誰……？"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SOLDIER_ADMIN_WHITE_NULL","text":{"KOREA":" 접니다, 부인.","JPN":" 私です、シュナイダー夫人。","ENG":"It's me, Mrs. Schneider.","TWN":"夫人，是我。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};